class PaymentScreen extends StatefulWidget {
  @override
  _PaymentScreenState createState() => _PaymentScreenState();
}

class _PaymentScreenState extends State<PaymentScreen> {
  final InAppPurchase _inAppPurchase = InAppPurchase.instance;
  final List<String> _productIds = ['product1', 'product2'];
  List<ProductDetails> _products = [];
  bool _isAvailable = false;

  @override
  void initState() {
    super.initState();
    _initializeInAppPurchase();
  }

  Future<void> _initializeInAppPurchase() async {
    final bool isAvailable = await _inAppPurchase.isAvailable();
    if (isAvailable) {
      final ProductDetailsResponse response = await _inAppPurchase.queryProductDetails(_productIds.toSet());
      if (response.notFoundIDs.isEmpty) {
        setState(() {
          _products = response.productDetails;
          _isAvailable = true;
        });
      }
    }
  }

  Future<void> _purchaseProduct(ProductDetails productDetails) async {
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: productDetails);
    _inAppPurchase.buyNonConsumable(purchaseParam: purchaseParam);
  }

  Future<void> _processStripePayment() async {
    try {
      final paymentIntent = await _createPaymentIntent('10', 'USD');
      await Stripe.instance.initPaymentSheet(paymentSheetParameters: SetupPaymentSheetParameters(paymentIntentClientSecret: paymentIntent['client_secret']));
      await Stripe.instance.presentPaymentSheet();
    } catch (e) {
      print('Error: $e');
    }
  }

  Future<Map<String, dynamic>> _createPaymentIntent(String amount, String currency) async {
    final response = await FirebaseFirestore.instance.collection('payments').add({'amount': amount, 'currency': currency});
    return response.data();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Payment Processing')),
      body: _isAvailable
          ? ListView.builder(
              itemCount: _products.length,
              itemBuilder: (context, index) {
                final product = _products[index];
                return ListTile(
                  title: Text(product.title),
                  subtitle: Text(product.price),
                  trailing: ElevatedButton(
                    onPressed: () => _purchaseProduct(product),
                    child: Text('Buy'),
                  ),
                );
              },
            )
          : Center(child: CircularProgressIndicator()),
      floatingActionButton: FloatingActionButton(
        onPressed: _processStripePayment,
        child: Icon(Icons.payment),
      ),
    );
  }
}